static const char *cb_query_source(const char *language) {
    if (strcmp(language, "javascript") == 0) return cb_query_javascript;
    if (strcmp(language, "jsx") == 0) return cb_query_jsx;
    if (strcmp(language, "typescript") == 0) return cb_query_typescript;
    if (strcmp(language, "tsx") == 0) return cb_query_tsx;
    if (strcmp(language, "python") == 0) return cb_query_python;
    if (strcmp(language, "kotlin") == 0) return cb_query_kotlin;
    if (strcmp(language, "swift") == 0) return cb_query_swift;
    if (strcmp(language, "bash") == 0) return cb_query_bash;
    if (strcmp(language, "c") == 0) return cb_query_c;
    if (strcmp(language, "css") == 0) return cb_query_css;
    if (strcmp(language, "go") == 0) return cb_query_go;
    if (strcmp(language, "html") == 0) return cb_query_html;
    if (strcmp(language, "java") == 0) return cb_query_java;
    if (strcmp(language, "json") == 0) return cb_query_json;
    if (strcmp(language, "markdown") == 0) return cb_query_markdown;
    if (strcmp(language, "ruby") == 0) return cb_query_ruby;
    if (strcmp(language, "rust") == 0) return cb_query_rust;
    return 0;
}

